 * Detects charset from BOM and returns the appropriate charset name.
 * This method also advances the byte buffer position past the BOM if one is found.
 * @param byteData the byte buffer to check for BOM
 * @return charset name if BOM is found, otherwise null
 */
static String detectCharsetFromBom(ByteBuffer byteData) {
    if (byteData.remaining() < 2) {
        return null;
    }

    // Save current position to restore if no BOM is found
    int startPosition = byteData.position();

    // Check for different BOMs in order
    // UTF-8 BOM: EF BB BF
    if (byteData.remaining() >= 3) {
        byte b1 = byteData.get();
        byte b2 = byteData.get();
        byte b3 = byteData.get();

        if (b1 == UTF_8_BOM_1 && b2 == UTF_8_BOM_2 && b3 == UTF_8_BOM_3) {
            return "UTF-8";
        }

        // Reset to start position to check other BOMs
        byteData.position(startPosition);
    }

    if (byteData.remaining() >= 2) {
        byte b1 = byteData.get();
        byte b2 = byteData.get();

        if (b1 == UTF_16BE_BOM_1 && b2 == UTF_16BE_BOM_2) {
            // Skip the BOM bytes
            return "UTF-16BE";
        } else if (b1 == UTF_16LE_BOM_1 && b2 == UTF_16LE_BOM_2) {
            // Skip the BOM bytes
            return "UTF-16LE";
        }

        // Reset to start position to check other BOMs
        byteData.position(startPosition);
    }

    // Check for UTF-32 BOMs - need at least 4 bytes
    if (byteData.remaining() >= 4) {
        byte b1 = byteData.get();
        byte b2 = byteData.get();
        byte b3 = byteData.get();
        byte b4 = byteData.get();

        if (b1 == UTF_32BE_BOM_1 && b2 == UTF_32BE_BOM_2 && b3 == UTF_32BE_BOM_3 && b4 == UTF_32BE_BOM_4) {
