            // Position is already after the 3-byte BOM
            return "UTF-8";
        }

        // Reset to start position to check other BOMs
        byteData.position(startPosition);
    }

    if (byteData.remaining() >= 2) {
        byte b1 = byteData.get();
        byte b2 = byteData.get();

        if (b1 == UTF_16BE_BOM_1 && b2 == UTF_16BE_BOM_2) {
            // Position is already after the 2-byte BOM
            // Check if the charset is supported
            if (Charset.isSupported("UTF-16BE")) {
                return "UTF-16BE";
            } else {
                // Fallback if UTF-16BE is not supported
                return "UTF-16";
            }
        } else if (b1 == UTF_16LE_BOM_1 && b2 == UTF_16LE_BOM_2) {
            // Position is already after the 2-byte BOM
            // Check if the charset is supported
