package org.jsoup.helper.steps;

import io.cucumber.java.en.*;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import static org.junit.Assert.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;

public class StepDefs {
    private Document document;
    private String fileContent;
    private String filePath;
    private Exception exception;

    @Given("the system environment is capable of reading files")
    public void the_system_environment_is_capable_of_reading_files() {
        // This is just a background setup step - no action needed
    }

    @Given("a file {string} containing UTF-16BE text with a BOM")
    public void a_file_containing_UTF_16BE_text_with_a_BOM(String fileName) throws IOException {
        // Create a file with UTF-16BE content and BOM
        filePath = fileName;
        File file = new File(fileName);
        file.getParentFile().mkdirs(); // Create directory if it doesn't exist

        // Create UTF-16BE text with BOM
        String content = "UTF-16BE title\n가각갂갃간갅 body text";

        // Write with BOM
        try (FileOutputStream fos = new FileOutputStream(file)) {
            // Write UTF-16BE BOM (0xFEFF in big endian)
            fos.write(new byte[]{(byte) 0xFE, (byte) 0xFF});
            // Write content as UTF-16BE
            byte[] contentBytes = content.getBytes(StandardCharsets.UTF_16BE);
            fos.write(contentBytes);
        }
    }

    @Given("a file {string} containing UTF-16LE text with a BOM")
    public void a_file_containing_UTF_16LE_text_with_a_BOM(String fileName) throws IOException {
        // Create a file with UTF-16LE content and BOM
        filePath = fileName;
        File file = new File(fileName);
        file.getParentFile().mkdirs(); // Create directory if it doesn't exist

        // Create UTF-16LE text with BOM
        String content = "UTF-16LE title\n가각갂갃간갅 body text";

        // Write with BOM
        try (FileOutputStream fos = new FileOutputStream(file)) {
            // Write UTF-16LE BOM (0xFEFF in little endian)
            fos.write(new byte[]{(byte) 0xFF, (byte) 0xFE});
            // Write content as UTF-16LE
            byte[] contentBytes = content.getBytes(StandardCharsets.UTF_16LE);
            fos.write(contentBytes);
        }
    }

    @Given("a file {string} containing UTF-32BE text with a BOM")
    public void a_file_containing_UTF_32BE_text_with_a_BOM(String fileName) throws IOException {
        // Create a file with UTF-32BE content and BOM
        filePath = fileName;
        File file = new File(fileName);
        file.getParentFile().mkdirs(); // Create directory if it doesn't exist

        // Create UTF-32BE text with BOM
        String content = "UTF-32BE title\n가각갂갃간갅 body text";

        // Write with BOM
        try (FileOutputStream fos = new FileOutputStream(file)) {
            // Write UTF-32BE BOM (0x0000FEFF in big endian)
            fos.write(new byte[]{(byte) 0x00, (byte) 0x00, (byte) 0xFE, (byte) 0xFF});
            // Write content in a way that simulates UTF-32 (not actually valid UTF-32)
            byte[] contentBytes = content.getBytes(StandardCharsets.UTF_8);
            fos.write(contentBytes);
        }
    }

    @Given("a file {string} containing UTF-32LE text with a BOM")
    public void a_file_containing_UTF_32LE_text_with_a_BOM(String fileName) throws IOException {
